const calendarios = $('Preparar Calendarios').all();
const resultados = [];
for (const item of $input.all()) {
  const ev = item.json;
  const pIdx = (item.pairedItem && typeof item.pairedItem.item === 'number') ? item.pairedItem.item : 0;
  const docInfo = calendarios[pIdx] ? calendarios[pIdx].json : {};
  const desc = ev.description || '';
  const match = desc.match(/Teléfono:\s*\+?(\d+)/i);
  const telefono = match ? match[1] : null;
  const inicioRaw = ev.start ? (ev.start.dateTime || ev.start.date) : null;
  const inicio = inicioRaw ? new Date(inicioRaw) : null;
  const horaStr = inicio ? inicio.toLocaleTimeString('es-VE',{hour:'2-digit',minute:'2-digit',hour12:false}) : '';
  const fechaStr = inicio ? inicio.toLocaleDateString('es-VE',{weekday:'long',day:'numeric',month:'long'}) : 'ma\u00f1ana';
  const pacienteNombre = (ev.summary || '').split(' - ')[1] || 'paciente';
  const lineas = [
    '\ud83e\uddb7 *Recordatorio de Cita \u2014 Implantarte*', '',
    'Hola *' + pacienteNombre + '*, tu cita es *ma\u00f1ana*:', '',
    '\ud83d\udc68\u200d\u2695\ufe0f ' + (docInfo.doctor || ''),
    '\ud83e\uddb7 ' + (docInfo.especialidad || ''),
    '\ud83d\udcc5 ' + fechaStr,
    '\ud83d\udd50 ' + horaStr + ' hrs', '',
    '\ud83d\udccd *Implantarte \u2014 Cl\u00ednica Dental*', '',
    '\ud83d\udccc *Recuerda:*',
    '\u2022 Llegar *10 minutos antes*',
    '\u2022 Traer c\u00e9dula de identidad',
    '\u2022 Para cancelar escribe *cancelar*', '',
    '\u00a1Te esperamos!'
  ];
  const mensaje = lineas.join('\n');
  resultados.push({ json: { telefono, mensaje, doctor: docInfo.doctor, paciente: pacienteNombre, tiene_telefono: !!telefono } });
}
return resultados;
